parameters.jsCode:
// @ts-nocheck
// Formata resultados da RPC search_ready_catalog_for_agent para o agente IA.
// Assinatura real: q_text, occasion_filter, category_slug_filter, max_budget_filter,
// same_day_filter, item_type_filter, limit_count, include_text_only
// Retorna: item_type, item_id, name, slug, price, cover_image_url, occasion_tags,
// availability_status, requires_confirmation, agent_readiness_status, match_score, ...

const catalogBase = $vars.CATALOG_BASE_URL || 'https://floricultura.vercel.app';

const items = $input.all();
let rawResults = [];

for (const item of items) {
  const d = item.json;
  if (Array.isArray(d)) {
    rawResults = d;
    break;
  }
  if (d && typeof d === 'object' && !d.error) {
    rawResults.push(d);
  }
}

if (rawResults.length === 0) {
  return [{
    json: {
      has_results: false,
      catalog_items: [],
      catalog_text: 'Não encontrei produtos disponíveis para essa busca no momento.',
      item_count: 0
    }
  }];
}

const formatted = rawResults.map(p => {
  const itemType = p.item_type || 'product';
  const slug = p.slug || '';
  const url = itemType === 'product'
    ? `${catalogBase}/produto/${slug}`
    : null;
  const priceNum = parseFloat(p.price) || 0;
  const priceFormatted = priceNum.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  return {
    item_type: itemType,
    item_id: p.item_id || p.id || null,
    name: p.name || '',
    slug: slug,
    short_description: p.short_description || '',
    price: priceNum,
    price_formatted: priceFormatted,
    cover_image_url: p.cover_image_url || null,
    availability_status: p.availability_status || 'available',
    requires_confirmation: Boolean(p.requires_confirmation),
    same_day_available: Boolean(p.same_day_available),
    occasion_tags: p.occasion_tags || [],
    agent_readiness_status: p.agent_readiness_status || 'ready',
    agent_notes: p.agent_notes || null,
    match_score: p.match_score || 0,
    catalog_url: url
  };
});

// Build text summary for IA reply
const lines = formatted.map((p, i) => {
  const num = i + 1;
  const urlPart = p.catalog_url ? `\n   🔗 ${p.catalog_url}` : '';
  const confirmPart = p.requires_confirmation ? ' *(disponibilidade sob consulta)*' : '';
  return `${num}. *${p.name}* — ${p.price_formatted}${confirmPart}${p.short_description ? '\n   ' + p.short_description : ''}${urlPart}`;
});

const catalogText = lines.join('\n\n');

return [{
  json: {
    has_results: formatted.length > 0,
    catalog_items: formatted,
    catalog_text: catalogText,
    item_count: formatted.length
  }
}];
